// Loaded AFTER mermaid CDN: preprocess dotted node IDs, then render
document.addEventListener("DOMContentLoaded", function () {
  if (typeof mermaid === "undefined") return;

  mermaid.initialize({ startOnLoad: false, theme: "default" });

  // Fix mkdocstrings inheritance diagrams: dotted Python module paths
  // (e.g. "pkg.mod.Class") are invalid mermaid node IDs.
  document.querySelectorAll("pre.mermaid code, div.mermaid code").forEach(function (code) {
    code.textContent = code.textContent.replace(
      /\b([a-zA-Z_]\w*(?:\.[a-zA-Z_]\w*)+)(?=[\[\(\{<\s]|$)/gm,
      function (m) { return m.replace(/\./g, "__"); }
    );
  });

  // Render all mermaid diagrams
  mermaid.run({
    querySelector: "pre.mermaid code, div.mermaid"
  });
});

