// Loaded AFTER mermaid CDN: preprocess and render mermaid diagrams
document.addEventListener("DOMContentLoaded", function () {
  if (typeof mermaid === "undefined") return;

  mermaid.initialize({ startOnLoad: false, theme: "default" });

  // fence_code_format wraps content in <pre><code class="language-mermaid">.
  // Mermaid can't render SVG properly inside <code>, so we move the source
  // into a <div class="mermaid"> and replace the original <pre>.
  document.querySelectorAll("code.language-mermaid").forEach(function (code) {
    var source = code.textContent;
    // Fix dotted Python module paths (e.g. "pkg.mod.Class") which are
    // invalid mermaid node IDs from mkdocstrings inheritance diagrams.
    source = source.replace(
      /\b([a-zA-Z_]\w*(?:\.[a-zA-Z_]\w*)+)(?=[\[\(\{<\s]|$)/gm,
      function (m) { return m.replace(/\./g, "__"); }
    );
    var div = document.createElement("div");
    div.className = "mermaid";
    div.textContent = source;
    var pre = code.parentElement;
    pre.parentElement.replaceChild(div, pre);
  });

  mermaid.run({ querySelector: ".mermaid" });
});

